{{familytree |border=0| | | | | | | | | | |`| 001 |-| 002 |-| 003 |-|v| 004 |001=[[百済王 (皇族)|百済王]]|002=某王|003='''[[#河内王 (飛鳥時代)|河内王]]'''|004=[[大原高安|高安王]]}}
{{familytree |border=0| | | | | | | | | | | | | | | | | | | | | | | |)| 001 |001=[[大原桜井|桜井王]]}}
{{familytree |border=0| | | | | | | | | | | | | | | | | | | | | | | |`| 001 |001=[[大原門部|門部王]]}}
